import "core-js/modules/es.array.push.js";
export default {
  name: 'OSIPicta',
  props: {
    windowId: {
      type: String,
      required: true
    },
    USERID: {
      type: Number,
      default: 0
    }
  },
  data() {
    return {
      images: [],
      isLoading: false,
      currentIndex: -1,
      translateX: 0,
      translateY: 0,
      infoPanelVisible: false,
      currentImageInfo: {}
    };
  },
  computed: {
    // получение данных конкретного изображения из массива images
    currentImage() {
      const curImg = this.images[this.currentIndex] || null;
      if (curImg) {
        this.currentImageInfo = {
          ...this.currentImage,
          width: img ? img.naturalWidth : 0,
          height: img ? img.naturalHeight : 0
        };
      }
      return curImg;
    },
    imageStyle() {
      if (!this.currentImage) return {};
      return {
        transform: `translate(${this.translateX}px, ${this.translateY}px) scale(${this.scale})`,
        transformOrigin: 'top left',
        // cursor: this.isDragging ? 'grabbing' : 'grab',
        opacity: this.isLoading ? 0.5 : 1
      };
    }
  },
  methods: {
    // throttle (раз в 2 сек.) ===
    throttledSaveState() {
      if (this.saveTimeout) clearTimeout(this.saveTimeout);
      this.saveTimeout = setTimeout(() => {
        // this.saveState();    //TODO - вернуть и реализовать
        this.saveTimeout = null;
      }, 2000);
    },
    openFilePicker() {
      this.$refs.fileInput.click();
    },
    // преобразование данных "из input`а"
    fileToDataUrl(file) {
      return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = e => resolve(e.target.result);
        reader.onerror = e => reject(e);
        reader.readAsDataURL(file);
      });
    },
    // ручной выбор файла
    async handleFileSelect(event) {
      const files = Array.from(event.target.files);
      await this.loadImages(files);
      event.target.value = '';
    },
    async loadImages(files) {
      this.isLoading = true;
      try {
        const newImages = [];
        for (const file of files) {
          const dataUrl = await this.fileToDataUrl(file);
          newImages.push({
            file,
            dataUrl,
            name: file.name,
            type: file.type,
            size: file.size,
            lastModified: file.lastModified
          });
        }
        this.images = [...this.images, ...newImages];
        if (this.images.length > 0 && this.currentIndex === -1) {
          this.currentIndex = 0;
          this.$nextTick(() => {
            this.fitToWindow();
          });
        }

        // this.saveState();    //TODO - вернуть и реализовать
      } catch (error) {
        console.error('Ошибка загрузки изображений:', error);
        alert('Не удалось загрузить изображения');
      } finally {
        this.isLoading = false;
      }
    },
    // центрирование изображения
    centerImage() {
      if (!this.$refs.image || !this.$refs.viewport) return;
      const viewport = this.$refs.viewport;
      const img = this.$refs.image;
      this.translateX = Math.max(0, (viewport.clientWidth - img.naturalWidth * this.scale) / 2);
      this.translateY = Math.max(0, (viewport.clientHeight - img.naturalHeight * this.scale) / 2);
    },
    fitToWindow() {
      if (!this.currentImage || !this.$refs.image) return;
      const viewport = this.$refs.viewport;
      const img = this.$refs.image;
      if (img.complete) {
        const scaleX = viewport.clientWidth / img.naturalWidth;
        const scaleY = viewport.clientHeight / img.naturalHeight;
        this.scale = Math.min(scaleX, scaleY, 1);
        this.centerImage();
        this.throttledSaveState();
      }
    },
    // saveState() {
    //     // Здесь логика сохранения состояния
    //     console.log('~saveState...');
    // },

    Chng_currentIndex(operVal) {
      let newVal = operVal;
      if (operVal && operVal === 'min' && this.currentIndex > 0) {
        newVal = this.currentIndex - 1;
      } else if (operVal && operVal === 'min') {
        newVal = 0;
      } else if (operVal && operVal === 'plus' && this.currentIndex < this.images.length - 1) {
        newVal = this.currentIndex + 1;
      } else if (operVal && operVal === 'plus') {
        newVal = this.images.length - 1;
      } else {
        newVal = this.currentIndex;
      }
      this.currentIndex = newVal;
      this.resetView();
    },
    resetView() {
      this.scale = 1;
      this.translateX = 0;
      this.translateY = 0;
    },
    onImageError() {
      alert('Не удалось загрузить изображение');
    }
  },
  mounted() {},
  beforeUnmount() {}
};
